+    #[test]
+    fn edge_alert_reason_equality() {
+        assert_eq!(AlertReason::Normal, AlertReason::Normal);
+        assert_eq!(
+            AlertReason::ConformalExceeded,
+            AlertReason::ConformalExceeded
+        );
+        assert_eq!(AlertReason::EProcessExceeded, AlertReason::EProcessExceeded);
