+    #[test]
+    fn edge_welford_variance_single_sample() {
+        let mut stats = CalibrationStats::new();
+        stats.update(42.0);
+        // With n=1, variance falls back to 1.0
+        assert!((stats.variance() - 1.0).abs() < f64::EPSILON);
+    }
